import{_ as e}from"./chunks/tang-nano-9k-pinout.DoQZmwRq.js";import{_ as t,o as i,c as r,a2 as o}from"./chunks/framework.BuL2a98s.js";const n="/unit_devlab_fpga_examples/assets/tang-nano-9k-board.TSKYb8Ig.png",s="/unit_devlab_fpga_examples/assets/tang-nano-9k-blocks.DCzTjqFA.jpg",f=JSON.parse('{"title":"Tang Nano 9K","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tang-nano-9k.md","filePath":"guide/tang-nano-9k.md"}'),l={name:"guide/tang-nano-9k.md"};function d(c,a,p,u,m,h){return i(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="tang-nano-9k" tabindex="-1">Tang Nano 9K <a class="header-anchor" href="#tang-nano-9k" aria-label="Permalink to &quot;Tang Nano 9K&quot;">​</a></h1><h2 id="informacion" tabindex="-1">Información <a class="header-anchor" href="#informacion" aria-label="Permalink to &quot;Información&quot;">​</a></h2><p>La <strong>Tang Nano 9K</strong> es una placa de desarrollo de <a href="https://uelectronics.com/sipeed/" target="_blank" rel="noreferrer">Sipeed</a> basada en el FPGA <strong>Gowin GW1NR-9</strong>. Permite diseñar, sintetizar, simular y probar circuitos digitales escritos en Verilog o VHDL. Combina la flexibilidad de un FPGA con un formato compacto, bajo consumo y costo accesible.</p><p><img src="'+n+'" alt="Vista de la placa Tang Nano 9K"></p><p>La placa incorpora un chip <strong>BL702</strong> que proporciona las interfaces USB-JTAG y USB-UART para el GW1NR-9. Un solo cable USB-C permite alimentar la tarjeta, programar el FPGA y utilizar la comunicación serie.</p><p>La Tang Nano 9K no incluye un procesador RISC-V físico. Sin embargo, su capacidad lógica permite implementar <em>softcores</em> RISC-V completos, como PicoRV, además de diseños lógicos convencionales.</p><h2 id="distribucion-de-la-placa" tabindex="-1">Distribución de la placa <a class="header-anchor" href="#distribucion-de-la-placa" aria-label="Permalink to &quot;Distribución de la placa&quot;">​</a></h2><p>El siguiente diagrama ayuda a identificar los principales componentes y conectores antes de comenzar una práctica.</p><p><img src="'+s+'" alt="Bloques funcionales de la Tang Nano 9K"></p><ul><li><strong>USB Type-C / BL702:</strong> alimentación, programación USB-JTAG y comunicación USB-UART.</li><li><strong>GW1NR-9:</strong> FPGA principal donde se implementa el circuito.</li><li><strong>Oscilador de 27 MHz:</strong> reloj disponible para los diseños.</li><li><strong>SPI Flash de 32 Mbit:</strong> almacenamiento no volátil externo.</li><li><strong>Conectores HDMI, RGB y SPI LCD:</strong> interfaces para proyectos de video y pantallas.</li><li><strong>Botones:</strong> dos entradas programables para el usuario.</li></ul><h2 id="especificaciones-y-caracteristicas" tabindex="-1">Especificaciones y características <a class="header-anchor" href="#especificaciones-y-caracteristicas" aria-label="Permalink to &quot;Especificaciones y características&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Especificación</th></tr></thead><tbody><tr><td>FPGA</td><td>Gowin GW1NR-LV9QN88PC6/I5</td></tr><tr><td>Unidades lógicas</td><td>8,640 LUT4</td></tr><tr><td>Registros</td><td>6,480 FF</td></tr><tr><td>Frecuencia del oscilador</td><td>27 MHz</td></tr><tr><td>Shadow SRAM</td><td>17,280 bits</td></tr><tr><td>Block SRAM</td><td>468 Kbits distribuidos en 26 bloques</td></tr><tr><td>Flash de usuario integrada</td><td>608 Kbits</td></tr><tr><td>PSRAM</td><td>64 Mbits</td></tr><tr><td>Recursos DSP</td><td>20 multiplicadores de 18 × 18 bits y acumulador de 54 bits</td></tr><tr><td>SPI Flash externa</td><td>32 Mbits</td></tr><tr><td>PLL</td><td>2</td></tr><tr><td>Interfaces de pantalla</td><td>HDMI, RGB y SPI</td></tr><tr><td>Almacenamiento extraíble</td><td>Ranura para tarjeta TF/microSD</td></tr><tr><td>Depurador</td><td>BL702 con USB-JTAG y USB-UART integrados</td></tr><tr><td>Conectores de expansión</td><td>Dos hileras de 24 pads, paso de 2.54 mm</td></tr><tr><td>Botones</td><td>2 programables</td></tr><tr><td>LED</td><td>6 programables</td></tr><tr><td>Dimensiones aproximadas</td><td>26 × 70 mm</td></tr></tbody></table><h3 id="entradas-y-salidas" tabindex="-1">Entradas y salidas <a class="header-anchor" href="#entradas-y-salidas" aria-label="Permalink to &quot;Entradas y salidas&quot;">​</a></h3><p>Las E/S admiten capacidades de manejo de <strong>4 mA, 8 mA, 16 mA y 24 mA</strong>. Cada E/S ofrece opciones independientes de <em>Bus Keeper</em>, resistencias <em>pull-up</em>/<em>pull-down</em> y salida <em>Open Drain</em>.</p><div class="warning custom-block"><p class="custom-block-title">Voltajes de los bancos</p><p>No todos los pines trabajan con el mismo voltaje. Verifica siempre el banco y el voltaje indicados en el pinout y el esquemático antes de conectar un periférico.</p></div><h2 id="pinout" tabindex="-1">Pinout <a class="header-anchor" href="#pinout" aria-label="Permalink to &quot;Pinout&quot;">​</a></h2><p>La imagen muestra el número de pin del encapsulado, el nombre de la E/S, las funciones multiplexadas y el voltaje de cada banco.</p><p><img src="'+e+'" alt="Pinout de la Tang Nano 9K"></p><p>Antes de modificar un archivo <code>.cst</code>, consulta la <a href="./cst">guía de archivos CST</a> y confirma que la señal corresponde al pin físico correcto.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La tarjeta puede utilizarse en:</p><ul><li>Prácticas de lógica combinacional y secuencial.</li><li>Diseño con Verilog y VHDL.</li><li>Control de pantallas RGB, SPI y HDMI.</li><li>Generación de video y conversión RGB-LCD.</li><li>Procesamiento matemático mediante recursos DSP.</li><li>Integración de periféricos mediante GPIO.</li><li>Implementación de <em>softcores</em> RISC-V, como PicoRV.</li></ul><h2 id="documentacion-y-recursos" tabindex="-1">Documentación y recursos <a class="header-anchor" href="#documentacion-y-recursos" aria-label="Permalink to &quot;Documentación y recursos&quot;">​</a></h2><ul><li><a href="https://wiki.sipeed.com/hardware/en/tang/Tang-Nano-9K/Nano-9K.html" target="_blank" rel="noreferrer">Wiki oficial de la Tang Nano 9K</a></li><li><a href="https://dl.sipeed.com/shareURL/TANG/Nano%209K/4_Dimensional_drawing" target="_blank" rel="noreferrer">Plano dimensional</a></li><li><a href="/unit_devlab_fpga_examples/guide/Tang_Nano_9k_3672_Schematic.pdf">Esquemático de la Tang Nano 9K</a></li><li><a href="https://github.com/sipeed/TangNano-9K-example" target="_blank" rel="noreferrer">Ejemplos oficiales de Sipeed</a></li><li><a href="https://dl.sipeed.com/fileList/TANG/Nano%209K/6_Chip_Manual/EN/General%20Guide/SUG100-2.6E_Gowin%20Software%20User%20Guide.pdf" target="_blank" rel="noreferrer">Guía de software Gowin</a></li><li><a href="https://dl.sipeed.com/shareURL/TANG/Nano%209K/" target="_blank" rel="noreferrer">Archivos de hardware de Sipeed</a></li><li><a href="https://wiki.sipeed.com/hardware/en/tang/common-doc/questions.html" target="_blank" rel="noreferrer">Preguntas frecuentes de la familia Tang</a></li></ul><h2 id="recomendaciones-de-uso" tabindex="-1">Recomendaciones de uso <a class="header-anchor" href="#recomendaciones-de-uso" aria-label="Permalink to &quot;Recomendaciones de uso&quot;">​</a></h2><h3 id="antes-de-conectar-la-tarjeta" tabindex="-1">Antes de conectar la tarjeta <a class="header-anchor" href="#antes-de-conectar-la-tarjeta" aria-label="Permalink to &quot;Antes de conectar la tarjeta&quot;">​</a></h3><ul><li>Descarga la electricidad estática de tu cuerpo antes de manipular la placa.</li><li>Verifica que el voltaje del periférico sea compatible con el banco GPIO utilizado.</li><li>Evita colocar la placa sobre superficies metálicas o conductoras.</li><li>Revisa que no haya líquidos, cables sueltos o piezas metálicas sobre la tarjeta.</li></ul><h3 id="durante-las-conexiones" tabindex="-1">Durante las conexiones <a class="header-anchor" href="#durante-las-conexiones" aria-label="Permalink to &quot;Durante las conexiones&quot;">​</a></h3><ul><li>Desconecta la alimentación antes de cambiar el cableado externo.</li><li>Inserta completamente y sin desplazamiento cualquier cable flexible FPC.</li><li>Evita utilizar los pines <strong>JTAG, MODE0/1 y DONE</strong>, salvo que el diseño lo requiera.</li><li>Ten presente que las E/S multiplexadas con HDMI incorporan resistencias <em>pull-up</em> y pueden comportarse de forma diferente al usarlas como GPIO.</li></ul><h3 id="soporte-y-comunidad" tabindex="-1">Soporte y comunidad <a class="header-anchor" href="#soporte-y-comunidad" aria-label="Permalink to &quot;Soporte y comunidad&quot;">​</a></h3><p>Para recibir ayuda, consulta primero las <a href="https://wiki.sipeed.com/hardware/en/tang/common-doc/questions.html" target="_blank" rel="noreferrer">preguntas frecuentes de Tang</a>. También puedes acudir al grupo de <a href="https://t.me/sipeed" target="_blank" rel="noreferrer">Telegram de Sipeed</a> o a la cuenta <a href="https://x.com/SipeedIO" target="_blank" rel="noreferrer">@SipeedIO</a>.</p><h2 id="siguiente-paso" tabindex="-1">Siguiente paso <a class="header-anchor" href="#siguiente-paso" aria-label="Permalink to &quot;Siguiente paso&quot;">​</a></h2><p>Consulta <a href="./entorno">Preparar el entorno</a> para instalar VS Code, Python y Git. Después sigue la guía de <a href="./devlab">DevLab</a> para compilar y cargar el primer ejemplo.</p>',33)])])}const _=t(l,[["render",d]]);export{f as __pageData,_ as default};
